"""Base agent functionality for PHAROS."""

from datetime import datetime
from typing import Any

from langchain_anthropic import ChatAnthropic
from langchain_core.messages import HumanMessage, SystemMessage

import sys
sys.path.insert(0, str(__file__).rsplit("/", 3)[0])
from config.settings import get_settings
from src.graph.state import PharosState


def get_llm() -> ChatAnthropic:
    """Get configured Claude LLM."""
    settings = get_settings()
    return ChatAnthropic(
        model=settings.anthropic_model,
        api_key=settings.anthropic_api_key,
        max_tokens=4096,
    )


def add_to_history(state: PharosState, agent: str, action: str, details: dict[str, Any] | None = None) -> None:
    """Add entry to state history."""
    history = state.get("history", [])
    history.append({
        "timestamp": datetime.utcnow().isoformat(),
        "agent": agent,
        "action": action,
        "details": details or {},
    })
    state["history"] = history
    state["updated_at"] = datetime.utcnow().isoformat()


def format_state_for_prompt(state: PharosState) -> str:
    """Format state into a readable string for prompts."""
    parts = [
        f"# Ticket: {state.get('ticket_id', 'N/A')}",
        f"**Title:** {state.get('title', 'N/A')}",
        f"**Description:** {state.get('description', 'N/A')}",
        f"**Status:** {state.get('status', 'draft')}",
        f"**Retry Count:** {state.get('retry_count', 0)}/{state.get('max_retries', 3)}",
    ]

    if state.get("feature_id"):
        parts.append(f"**Feature ID:** {state['feature_id']}")

    if state.get("visual_spec"):
        parts.append("\n## Visual Specification")
        spec = state["visual_spec"]
        if spec.get("description"):
            parts.append(f"- Description: {spec['description']}")
        if spec.get("expected_elements"):
            parts.append(f"- Expected Elements: {', '.join(spec['expected_elements'])}")
        if spec.get("wording"):
            parts.append(f"- Wording: {spec['wording']}")

    if state.get("technical_spec"):
        parts.append("\n## Technical Specification")
        spec = state["technical_spec"]
        if spec.get("requirements"):
            parts.append("- Requirements:")
            for req in spec["requirements"]:
                parts.append(f"  - {req}")
        if spec.get("acceptance_criteria"):
            parts.append("- Acceptance Criteria:")
            for ac in spec["acceptance_criteria"]:
                parts.append(f"  - {ac}")

    if state.get("implementation"):
        parts.append("\n## Implementation")
        impl = state["implementation"]
        if impl.get("approach"):
            parts.append(f"- Approach: {impl['approach']}")
        if impl.get("files_changed"):
            parts.append(f"- Files Changed: {', '.join(impl['files_changed'])}")

    if state.get("audit"):
        parts.append("\n## Audit Results")
        audit = state["audit"]
        if audit.get("visual_passed") is not None:
            parts.append(f"- Visual: {'PASS' if audit['visual_passed'] else 'FAIL'}")
        if audit.get("performance_passed") is not None:
            parts.append(f"- Performance: {'PASS' if audit['performance_passed'] else 'FAIL'}")
        if audit.get("qa_passed") is not None:
            parts.append(f"- QA: {'PASS' if audit['qa_passed'] else 'FAIL'}")

    if state.get("rejection_reasons"):
        parts.append("\n## Rejection Reasons")
        for reason in state["rejection_reasons"]:
            parts.append(f"- {reason}")

    return "\n".join(parts)

